lang_codes = ['ja', 'ko', 'ru', 'fr', 'de']
for lang in lang_codes:
    with open(f'app_{lang}.arb', 'r', encoding='utf-8') as f:
        data = json.load(f)
    count = 0
    for key, translations in T.items():
        if key in data and lang in translations:
            data[key] = translations[lang]
            count += 1
    with open(f'app_{lang}.arb', 'w', encoding='utf-8') as f:
        json.dump(data, f, ensure_ascii=False, indent=2)
    print(f'{lang}: {count} strings translated')

print('Done!')
